msgContent:
{
  "content": "【{$companyName} 数据周报】\n\n亲爱的 {$userName}：\n\n上周（{$startDate} - {$endDate}）平台整体表现如下：\n1. 新增用户：{$newUsers} 人 (环比 {$growthRate}%)\n2. 活跃用户：{$activeUsers} 人\n3. 服务器响应时间：{$avgResponseTime}ms\n\n详细报表请点击：{$reportLink}\n\n祝您新的一周工作愉快！",
  "content_params_schema": [
    {
      "key": "companyName",
      "description": "公司名称",
      "type": "string",
      "required": true,
      "defaultValue": "我们的公司"
    },
    {
      "key": "userName",
      "description": "收件人姓名",
      "type": "string",
      "required": true,
      "defaultValue": "用户"
    },
    {
      "key": "startDate",
      "description": "统计开始日期",
      "type": "string",
      "required": true,
      "defaultValue": ""
    },
    {
      "key": "endDate",
      "description": "统计结束日期",
      "type": "string",
      "required": true,
      "defaultValue": ""
    },
    {
      "key": "newUsers",
      "description": "新增用户数",
      "type": "number",
      "required": true,
      "defaultValue": "0"
    },
    {
      "key": "growthRate",
      "description": "环比增长率",
      "type": "string",
      "required": false,
      "defaultValue": "+0%"
    },
    {
      "key": "activeUsers",
      "description": "活跃用户数",
      "type": "number",
      "required": true,
      "defaultValue": "0"
    },
    {
      "key": "avgResponseTime",
      "description": "平均响应时间",
      "type": "number",
      "required": true,
      "defaultValue": "0"
    },
    {
      "key": "reportLink",
      "description": "报表详情链接",
      "type": "string",
      "required": true,
      "defaultValue": ""
    }
  ],
  "extra_params_schema": [
    {
      "key": "title",
      "description": "邮件标题",
      "type": "string",
      "required": true,
      "defaultValue": "运营周报"
    },
    {
      "key": "url",
      "description": "邮件附件地址，多个以逗号分隔",
      "type": "string",
      "required": false,
      "defaultValue": ""
    }
  ]
}
